package scanner

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/google/uuid"
	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"

	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/core/artwork"
	"github.com/navidrome/navidrome/log"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/server/events"
	"github.com/navidrome/navidrome/tests"
)

func TestScannerIntegration(t *testing.T) {
	tests.Init(t, true)
	log.SetLevel(log.LevelFatal)
	RegisterFailHandler(Fail)
	RunSpecs(t, "Scanner Integration Suite")
}

var _ = Describe("Scanner Integration Tests", func() {
	var (
		ctx        context.Context
		tempDir    string
		lib        model.Library
		mediaRepo  *tests.MockMediaFileRepo
		albumRepo  *tests.MockAlbumRepo
		artistRepo *tests.MockArtistRepo
		ds         *tests.MockDataStore
		mockBroker *MockEventBroker
	)

	BeforeEach(func() {
		ctx = context.Background()

		// Create a temporary directory for test fixtures
		var err error
		tempDir, err = os.MkdirTemp("", "navidrome-scan-test-*")
		Expect(err).NotTo(HaveOccurred())

		// Set up the test library
		lib = model.Library{
			ID:         1,
			Name:       "Test Library",
			Path:       tempDir,
			LastScanAt: time.Time{},
		}

		// Set up mock repositories
		mediaRepo = tests.CreateMockMediaFileRepo()
		albumRepo = tests.CreateMockAlbumRepo()
		artistRepo = tests.CreateMockArtistRepo()
		mockBroker = &MockEventBroker{}

		ds = &tests.MockDataStore{
			MockedMediaFile: mediaRepo,
			MockedAlbum:     albumRepo,
			MockedArtist:    artistRepo,
		}

		// Configure conf for scanner
		conf.Server.Scanner.Extractor = "taglib"
	})

	AfterEach(func() {
		if tempDir != "" {
			os.RemoveAll(tempDir)
		}
	})

	Describe("Full scan with audio files", func() {
		It("should scan and extract metadata from audio files", func() {
			// Create test audio files with metadata
			audioFile1 := createTestAudioFile(tempDir, "song1.mp3", "Test Song 1", "Test Artist", "Test Album", 1, 2023)
			audioFile2 := createTestAudioFile(tempDir, "song2.mp3", "Test Song 2", "Test Artist", "Test Album", 2, 2023)

			Expect(audioFile1).To(BeAnExistingFile())
			Expect(audioFile2).To(BeAnExistingFile())

			// Create scanner and scan
			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)), "should detect changes")

			// Verify mediafiles were stored
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(2))

			// Verify metadata extraction
			filesByPath := make(map[string]model.MediaFile)
			for _, mf := range allFiles {
				filesByPath[mf.Path] = mf
			}

			// Check first file
			mf1, ok := filesByPath[audioFile1]
			Expect(ok).To(BeTrue(), "first audio file should be in database")
			Expect(mf1.Title).To(ContainSubstring("Test Song 1"))
			Expect(mf1.Artist).To(ContainSubstring("Test Artist"))
			Expect(mf1.Album).To(ContainSubstring("Test Album"))
			Expect(mf1.TrackNumber).To(Equal(1))
			Expect(mf1.Year).To(Equal(2023))

			// Check second file
			mf2, ok := filesByPath[audioFile2]
			Expect(ok).To(BeTrue(), "second audio file should be in database")
			Expect(mf2.Title).To(ContainSubstring("Test Song 2"))
			Expect(mf2.TrackNumber).To(Equal(2))
		})
	})

	Describe("Incremental scan with no changes", func() {
		It("should not detect changes when files are unchanged", func() {
			// Create and scan audio files on first pass
			audioFile := createTestAudioFile(tempDir, "song.mp3", "Title", "Artist", "Album", 1, 2023)
			Expect(audioFile).To(BeAnExistingFile())

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			// First scan
			changeCount1, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount1).To(BeGreaterThan(int64(0)))

			initialFileCount := len(mediaRepo.data)
			Expect(initialFileCount).To(BeGreaterThan(0))

			// Update library LastScanAt to current time
			lib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Second scan with no changes to files
			scanner2 := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress2 := make(chan uint32, 100)
			changeCount2, err := scanner2.Scan(ctx, lib, false, progress2)
			close(progress2)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount2).To(Equal(int64(0)), "should detect no changes when files are unchanged")

			// Verify database state unchanged
			finalFileCount := len(mediaRepo.data)
			Expect(finalFileCount).To(Equal(initialFileCount))
		})
	})

	Describe("File deletion detection", func() {
		It("should remove deleted files from database", func() {
			// Create and scan two audio files
			audioFile1 := createTestAudioFile(tempDir, "song1.mp3", "Title 1", "Artist", "Album", 1, 2023)
			audioFile2 := createTestAudioFile(tempDir, "song2.mp3", "Title 2", "Artist", "Album", 2, 2023)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			// First scan - both files present
			_, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())

			fileCountAfterFirstScan := len(mediaRepo.data)
			Expect(fileCountAfterFirstScan).To(Equal(2))

			// Delete one file
			err = os.Remove(audioFile1)
			Expect(err).NotTo(HaveOccurred())

			// Update library LastScanAt
			lib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Second scan - one file deleted
			scanner2 := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress2 := make(chan uint32, 100)
			changeCount, err := scanner2.Scan(ctx, lib, false, progress2)
			close(progress2)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)), "should detect deletion")

			// Verify the deleted file was removed from database
			// Note: In real implementation, the file would be deleted via s.ds.MediaFile(ctx).Delete()
			// We verify this by checking that at least one file is still in the database
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(allFiles)).To(BeLessThanOrEqualTo(fileCountAfterFirstScan))
		})
	})

	Describe("Album and artist record creation", func() {
		It("should create album and artist records from metadata", func() {
			// Create multiple songs by same artist in same album
			createTestAudioFile(tempDir, "track1.mp3", "Track 1", "The Beatles", "Abbey Road", 1, 1969)
			createTestAudioFile(tempDir, "track2.mp3", "Track 2", "The Beatles", "Abbey Road", 2, 1969)
			createTestAudioFile(tempDir, "track3.mp3", "Track 3", "The Beatles", "Abbey Road", 3, 1969)

			scanner := NewTagScanner(ds, nil, &MockCacheWarmer{})
			progress := make(chan uint32, 100)

			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			close(progress)

			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)))

			// Verify media files were created with proper album/artist IDs
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(3))

			// All files should have same AlbumID and ArtistID
			var albumID string
			var artistID string
			for _, mf := range allFiles {
				if albumID == "" {
					albumID = mf.AlbumID
					artistID = mf.ArtistID
				}
				Expect(mf.AlbumID).To(Equal(albumID), "all tracks should have same album ID")
				Expect(mf.ArtistID).To(Equal(artistID), "all tracks should have same artist ID")
				Expect(mf.Album).To(ContainSubstring("Abbey Road"))
				Expect(mf.Artist).To(ContainSubstring("The Beatles"))
			}
		})
	})

	Describe("Handling empty directories", func() {
		It("should not process empty directories", func() {
