			close(progress)

			Expect(err).NotTo(HaveOccurred())

			// Verify only valid file was processed
			allFiles, err := mediaRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(1))

			// Verify it's the valid file
