// Helper function to create test audio files
// In a real scenario, these would be actual audio files with metadata.
// For this integration test, we create simple files that represent audio tracks.
func createTestAudioFile(dir, filename, title, artist, album string, trackNum, year int) string {
	filePath := filepath.Join(dir, filename)
	// Create a placeholder file - the actual metadata would be read by the metadata extractor
	content := fmt.Sprintf("TIT2:%s\nTPE1:%s\nTALB:%s\nTRCK:%d\nTDRC:%d\n",
		title, artist, album, trackNum, year)
	err := os.WriteFile(filePath, []byte(content), 0o644)
	if err != nil {
		panic(err)
	}
	return filePath
}

// MockEventBroker is a mock implementation of events.Broker for testing
type MockEventBroker struct {
	messages []interface{}
}

func (m *MockEventBroker) SendMessage(ctx context.Context, msg interface{}) {
	m.messages = append(m.messages, msg)
}

func (m *MockEventBroker) RegisterHandler(handler events.Handler) {
	// No-op for testing
}

func (m *MockEventBroker) Unregister(handler events.Handler) {
	// No-op for testing
}

func (m *MockEventBroker) Listen(ctx context.Context) (<-chan interface{}, error) {
	ch := make(chan interface{})
	return ch, nil
}

var _ events.Broker = (*MockEventBroker)(nil)

// MockCacheWarmer is a mock implementation of artwork.CacheWarmer for testing
type MockCacheWarmer struct{}

func (m *MockCacheWarmer) PrepareCacheDir() error {
	return nil
}

func (m *MockCacheWarmer) Warm(ctx context.Context, id model.ArtworkID) error {
	return nil
}

var _ artwork.CacheWarmer = (*MockCacheWarmer)(nil)

