// Helper function to create test audio files
// In a real scenario, these would be actual audio files with metadata.
// For this integration test, we create simple files that represent audio tracks.
func createTestAudioFile(dir, filename, title, artist, album string, trackNum, year int) string {
	filePath := filepath.Join(dir, filename)
	// Create a placeholder file - the actual metadata would be read by the metadata extractor
	content := fmt.Sprintf("TIT2:%s\nTPE1:%s\nTALB:%s\nTRCK:%d\nTDRC:%d\n",
		title, artist, album, trackNum, year)
	err := os.WriteFile(filePath, []byte(content), 0o644)
	if err != nil {
		panic(err)
	}
	return filePath
}

